void reverse(struct Node **head) {
 struct Node *prev = NULL;
 struct Node *current = *head;
 struct Node *next = NULL;

 while(current != NULL) {
 next = current->next; // Save next node
 current->next = prev; // Reverse the link
 prev = current; // Move prev one step
 current = next; // Move current one step
 }

 *head = prev; // prev is now the new head
}

// Recursive version
struct Node* reverseRecursive(struct Node *head) {
 if(head == NULL || head->next == NULL) {
 return head;
 }

 struct Node *newHead = reverseRecursive(head->next);
 head->next->next = head;
 head->next = NULL;

 return newHead;
}

public void reverse() {
 Node prev = null;
 Node current = head;
 Node next = null;

 while(current != null) {
 next = current.next;
 current.next = prev;
 prev = current;
 current = next;
 }

 head = prev;
}

